import{_ as t,c as n,o as e,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"FAQ: 자주 묻는 질문과 문제 해결 | OpenSkills","description":"OpenSkills의 자주 묻는 질문과 문제 해결 방법을 학습하세요. 설치 및 구성 문제를 빠르게 파악하고 해결하며, CLI 설계 철학의 기술적 결정을 이해합니다.","frontmatter":{"title":"FAQ: 자주 묻는 질문과 문제 해결 | OpenSkills","sidebarTitle":"문제가 발생했을 때","subtitle":"FAQ: 자주 묻는 질문과 문제 해결","description":"OpenSkills의 자주 묻는 질문과 문제 해결 방법을 학습하세요. 설치 및 구성 문제를 빠르게 파악하고 해결하며, CLI 설계 철학의 기술적 결정을 이해합니다.","order":4},"headers":[],"relativePath":"ko/numman-ali/openskills/faq/index.md","filePath":"ko/numman-ali/openskills/faq/index.md"}'),l={name:"ko/numman-ali/openskills/faq/index.md"};function i(o,a,r,p,d,h){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="자주-묻는-질문" tabindex="-1">자주 묻는 질문 <a class="header-anchor" href="#자주-묻는-질문" aria-label="Permalink to &quot;자주 묻는 질문&quot;">​</a></h1><p>이 장에서는 OpenSkills 사용 중 발생하는 자주 묻는 질문, 문제 해결 방법 및 설계 철학에 대한 설명을 수집하여 문제를 빠르게 파악하고 해결하는 데 도움을 드립니다.</p><h2 id="이-장의-내용" tabindex="-1">이 장의 내용 <a class="header-anchor" href="#이-장의-내용" aria-label="Permalink to &quot;이 장의 내용&quot;">​</a></h2><div class="grid-cards"><h3 id="자주-묻는-질문-1" tabindex="-1"><a href="./faq/">자주 묻는 질문</a> <a class="header-anchor" href="#자주-묻는-질문-1" aria-label="Permalink to &quot;[자주 묻는 질문](./faq/)&quot;">​</a></h3><p>설치, 구성, 사용 등에 대한 일반적인 질문에 답변합니다. OpenSkills와 Claude Code의 차이점, 스킬 설치 위치, AGENTS.md 동기화 문제, 다중 프로젝트 스킬 공유 등을 포함합니다.</p><h3 id="문제-해결" tabindex="-1"><a href="./troubleshooting/">문제 해결</a> <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;[문제 해결](./troubleshooting/)&quot;">​</a></h3><p>일반적인 오류의 진단 및 수정 방법을 제공합니다. Git clone 실패, SKILL.md를 찾을 수 없음, 스킬을 찾을 수 없음, 권한 오류, 업데이트 건너뛰기 등의 문제에 대한 자세한 해결 단계를 다룹니다.</p><h3 id="왜-cli인가" tabindex="-1"><a href="./why-cli-not-mcp/">왜 CLI인가?</a> <a class="header-anchor" href="#왜-cli인가" aria-label="Permalink to &quot;[왜 CLI인가?](./why-cli-not-mcp/)&quot;">​</a></h3><p>OpenSkills가 MCP 대신 CLI를 선택한 설계 이유를 설명합니다. 두 가지의 위치 차이를 심층 비교하고 스킬 시스템이 정적 파일 모드에 더 적합한 이유를 이해합니다.</p></div><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>문제가 발생했나요?</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 사용 방법을 모름 ──────────→ 자주 묻는 질문</span></span>
<span class="line"><span>    │                           (개념, 구성, 사용 팁)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 오류 발생 ────────────────→ 문제 해결</span></span>
<span class="line"><span>    │                           (오류 진단, 수정 단계)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─ 설계 철학을 알고 싶음 ────────→ 왜 CLI인가?</span></span>
<span class="line"><span>                                 (기술 선택, 아키텍처 결정)</span></span></code></pre></div><p><strong>권장 순서</strong>:</p><ol><li><strong>먼저 자주 묻는 질문 보기</strong> → 핵심 개념과 사용 팁을 빠르게 이해</li><li><strong>오류 발생 시 문제 해결 보기</strong> → 오류 메시지로 솔루션 검색</li><li><strong>심층 이해를 위해 설계 철학 보기</strong> → CLI vs MCP 기술적 고려사항 이해</li></ol><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">먼저 완료하는 것을 권장합니다</p><ul><li><a href="./../start/quick-start/">빠른 시작</a> - 기본 사용 흐름 이해</li><li><a href="./../start/installation/">OpenSkills 설치</a> - 환경 구성이 올바른지 확인</li></ul></div><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 완료한 후에는:</p><ul><li><strong>고급 기능 탐색</strong> → <a href="./../advanced/">고급 튜토리얼</a>에서 Universal 모드, 사용자 정의 스킬 등 학습</li><li><strong>명령 참조 확인</strong> → <a href="./../appendix/cli-api/">CLI API 참조</a>에서 전체 명령 문서 확인</li><li><strong>버전 업데이트 확인</strong> → <a href="./../changelog/changelog/">변경 로그</a>에서 새로운 기능 및 변경사항 확인</li></ul><hr><h2 id="빠른-탐색" tabindex="-1">빠른 탐색 <a class="header-anchor" href="#빠른-탐색" aria-label="Permalink to &quot;빠른 탐색&quot;">​</a></h2><table tabindex="0"><thead><tr><th>문제 유형</th><th>답변 찾기</th></tr></thead><tbody><tr><td>&quot;OpenSkills란 무엇인가요?&quot;</td><td><a href="./faq/">자주 묻는 질문</a></td></tr><tr><td>&quot;스킬은 어디에 설치되나요?&quot;</td><td><a href="./faq/">자주 묻는 질문</a></td></tr><tr><td>&quot;Git clone 실패&quot;</td><td><a href="./troubleshooting/">문제 해결</a></td></tr><tr><td>&quot;SKILL.md를 찾을 수 없음&quot;</td><td><a href="./troubleshooting/">문제 해결</a></td></tr><tr><td>&quot;왜 MCP를 사용하지 않나요?&quot;</td><td><a href="./why-cli-not-mcp/">왜 CLI인가?</a></td></tr></tbody></table>`,16)])])}const f=t(l,[["render",i]]);export{u as __pageData,f as default};
